/// ConnectionManager handles the RTMP connection lifecycle:
/// - Connecting to the RTMP server
/// - Detecting network drops
/// - Auto-reconnecting with exponential backoff + jitter
/// - Monitoring network availability via NWPathMonitor
///
/// IMPORTANT: ConnectionManager does NOT own the stream state.
/// It submits "intents" (requests) to the StreamingEngine, which
/// is the single source of truth for all state changes.
///
/// Reconnect behavior:
/// - On network drop: start exponential backoff (3s, 6s, 12s, ..., 60s cap)
/// - On NWPathMonitor "network available": try immediately (skip timer)
/// - On auth failure: NEVER retry (wrong credentials won't fix themselves)
/// - On user stop: cancel ALL pending reconnects immediately
final class ConnectionManager {

    /// The reconnect policy (exponential backoff with jitter)
    private let reconnectPolicy: ReconnectPolicy

    /// NWPathMonitor watches for network connectivity changes
    private let pathMonitor: NWPathMonitor
    private let monitorQueue: DispatchQueue

    /// Current network status
    @Published private(set) var isNetworkAvailable: Bool = true

    /// Current reconnect attempt number (0 = not reconnecting)
    private(set) var currentAttempt: Int = 0

    /// Timer for the next reconnect attempt
    private var reconnectTask: Task<Void, Never>?

    /// Whether we should be attempting to reconnect
    private var shouldReconnect: Bool = false

    // Callback to notify engine of connection events
    var onConnectionEvent: ((ConnectionEvent) -> Void)?

    enum ConnectionEvent {
        case connected
        case disconnected(reason: StopReason)
        case reconnecting(attempt: Int, nextRetryMs: Int64)
        case networkAvailable
        case networkUnavailable
    }

    init(reconnectPolicy: ReconnectPolicy = ExponentialBackoffReconnectPolicy()) { ... }

    /// Start monitoring network status
    func startMonitoring() { ... }

    /// Stop monitoring and cancel all reconnects
    func stopMonitoring() { ... }

    /// Begin reconnect sequence after connection loss
    func beginReconnect() { ... }

    /// Cancel all pending reconnect attempts (called on user stop or auth failure)
    func cancelReconnect() { ... }

    /// Handle a connection failure
    func handleConnectionFailure(reason: StopReason) {
        // If auth failure → cancel, never retry
        // If network error → begin reconnect
    }

    deinit {
        stopMonitoring()
    }
}
```

Key behaviors:
1. **NWPathMonitor**: Monitor on a background queue. When `path.status == .satisfied`, if we're in reconnect mode, attempt immediately.
2. **Exponential backoff**: Use `Task.sleep` for delays. Use `Task.isCancelled` to check for cancellation.
3. **Auth failure**: Immediately stop, never retry (wrong credentials won't fix themselves)
4. **User stop**: Cancel the reconnect Task, reset attempt counter
5. **Thread safety**: All reconnect state changes should be serialized

